-- 030_science_physics_en.sql
-- MindScrolling — Science Mode: Physics (English)
-- 250 quotes, sub_category = 'physics', content_type = 'science', lang = 'en'
-- Run in Supabase SQL Editor

BEGIN;

INSERT INTO quotes (id, text, author, category, lang, swipe_dir, pack_name, is_premium, content_type, sub_category, tags, is_hidden_mode, locked_by) VALUES

-- Albert Einstein (40 quotes)
(gen_random_uuid(), 'Imagination is more important than knowledge. Knowledge is limited. Imagination encircles the world.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The most beautiful thing we can experience is the mysterious. It is the source of all true art and science.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'creativity'], true, 'science'),
(gen_random_uuid(), 'God does not play dice with the universe.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The theory of relativity occurred to me by intuition, and music is the driving force behind this intuition.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Energy cannot be created or destroyed; it can only be changed from one form to another.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Space and time are not conditions in which we live, but modes by which we think.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The distinction between past, present and future is only a stubbornly persistent illusion.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'When you are courting a nice girl an hour seems like a second. When you sit on a red-hot cinder a second seems like an hour. That''s relativity.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Everything should be made as simple as possible, but not simpler.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'focus', 'learning'], true, 'science'),
(gen_random_uuid(), 'Gravitation is not responsible for people falling in love.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Pure mathematics is, in its way, the poetry of logical ideas.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The important thing is not to stop questioning. Curiosity has its own reason for existing.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'A person who never made a mistake never tried anything new.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['self_improvement', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The faster you go, the shorter you are.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Reality is merely an illusion, albeit a very persistent one.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Two things are infinite: the universe and human stupidity; and I''m not sure about the universe.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The most incomprehensible thing about the universe is that it is comprehensible.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Look deep into nature, and then you will understand everything better.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'If you can''t explain it simply, you don''t understand it well enough.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'wisdom', 'focus'], true, 'science'),
(gen_random_uuid(), 'I have no special talent. I am only passionately curious.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'self_improvement', 'learning'], true, 'science'),
(gen_random_uuid(), 'The measure of intelligence is the ability to change.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['self_improvement', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'It is strange to be known so universally and yet to be so lonely.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The whole of science is nothing more than a refinement of everyday thinking.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Coincidence is God''s way of remaining anonymous.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Logic will get you from A to B. Imagination will take you everywhere.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Science without religion is lame; religion without science is blind.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'The only source of knowledge is experience.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'wisdom', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'In the middle of every difficulty lies opportunity.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['self_improvement', 'wisdom', 'discipline'], true, 'science'),
(gen_random_uuid(), 'Once we accept our limits, we go beyond them.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['self_improvement', 'discipline', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Time is an illusion.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Mass and energy are both but different manifestations of the same thing.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The field equations of gravitation are the most beautiful and profound expression of nature''s laws.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'A question that sometimes drives me hazy: am I or are the others crazy?', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The eternal mystery of the world is its comprehensibility.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Any fool can know. The point is to understand.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Nature hides her secrets because of her essential loftiness, but not by means of ruse.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The speed of light is the ultimate speed limit in the universe.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Equations are more important to me than politics because politics is for the present, but equations are for eternity.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'focus', 'learning'], true, 'science'),
(gen_random_uuid(), 'Physical concepts are free creations of the human mind, and are not, however it may seem, uniquely determined by the external world.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'As far as the laws of mathematics refer to reality, they are not certain; and as far as they are certain, they do not refer to reality.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),

-- Richard Feynman (30 quotes)
(gen_random_uuid(), 'If you think you understand quantum mechanics, you don''t understand quantum mechanics.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Physics is like sex: sure, it may give some practical results, but that''s not why we do it.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The atoms come together, make structures, and the structures have properties that depend on the way the atoms are put together.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'When you get as old as I am, you start to realize you''ve told most of the good stuff you know to other people anyway.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'There is pleasure in recognizing old things from a new point of view.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Nature has a great simplicity and therefore a great beauty.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'What I cannot create, I do not understand.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'curiosity', 'creativity'], true, 'science'),
(gen_random_uuid(), 'I learned very early the difference between knowing the name of something and knowing something.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'wisdom', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'The uncertainty principle is not a statement about the accuracy of our instruments, it is a statement about nature itself.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'All things are made of atoms — little particles that move around in perpetual motion, attracting each other when they are a little distance apart, but repelling upon being squeezed into one another.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'We are explorers of a new and vast universe, and the frontier is everywhere.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'It doesn''t matter how beautiful your theory is, it doesn''t matter how smart you are. If it doesn''t agree with experiment, it''s wrong.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'discipline'], true, 'science'),
(gen_random_uuid(), 'The worthwhile problems are the ones you can really solve or help solve, the ones you can really contribute something to.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['focus', 'discipline', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'There''s a pleasure in physics and I don''t see why we should deny ourselves that pleasure.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'creativity'], true, 'science'),
(gen_random_uuid(), 'Fall in love with some activity, and do it! Nobody ever figures out what life is all about, and it doesn''t matter.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'self_improvement', 'discipline'], true, 'science'),
(gen_random_uuid(), 'I think it is much more interesting to live not knowing than to have answers that might be wrong.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The electron does anything it likes. It just goes in any direction at any speed, forward or backward in time.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Quantum mechanics describes nature as absurd from the point of view of common sense. And yet it fully agrees with experiment.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'I was born not knowing and have had only a little time to change that here and there.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'curiosity', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Science is the culture of doubt.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The highest forms of understanding we can achieve are laughter and human compassion.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'To those who do not know mathematics it is difficult to get across a real feeling as to the beauty, the deepest beauty of nature.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'In physics, you don''t have to go around making trouble for yourself; nature does it for you.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'There is nothing that living things do that cannot be understood from the point of view that they are made of atoms.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The most amazing thing is that we can do science at all. We can understand nature.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wonder', 'learning'], true, 'science'),
(gen_random_uuid(), 'Theoretical physicists live in a classical, Newtonian world. The quantum world is a foreign country.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'There are 10^11 stars in the galaxy. That used to be a huge number. But it''s only a hundred billion.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Poets say science takes away from the beauty of the stars — mere globs of gas atoms. Nothing is mere.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'I don''t know what''s the matter with people: they don''t learn by understanding; they learn by some other way — by rote or something.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'wisdom', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'It is in the admission of ignorance and the admission of uncertainty that there is a hope for the continuous motion of human beings in some direction that doesn''t ultimately box them in.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),

-- Stephen Hawking (25 quotes)
(gen_random_uuid(), 'However difficult life may seem, there is always something you can do and succeed at.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['self_improvement', 'discipline', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Look up at the stars and not down at your feet. Try to make sense of what you see.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Intelligence is the ability to adapt to change.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['self_improvement', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'We are just an advanced breed of monkeys on a minor planet of a very average star. But we can understand the universe. That makes us something very special.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Black holes ain''t as black as they are painted. They are not the eternal prisons they were once thought.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The universe does not allow perfection.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Not only does God play dice, but... He sometimes throws the dice where they cannot be seen.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'If time travel is possible, where are the tourists from the future?', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The greatest enemy of knowledge is not ignorance, it is the illusion of knowledge.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Life would be tragic if it weren''t funny.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'I have noticed even people who claim everything is predestined, and that we can do nothing to change it, look before they cross the road.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'A universe with a beginning does not preclude a creator.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The past, like the future, is indefinite and exists only as a spectrum of possibilities.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'When one''s expectations are reduced to zero, one really appreciates everything one does have.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'self_improvement', 'learning'], true, 'science'),
(gen_random_uuid(), 'My goal is simple. It is a complete understanding of the universe, why it is as it is and why it exists at all.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'focus', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Quiet people have the loudest minds.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Space and time are dynamic quantities: when a body moves, or a force acts, it affects the curvature of space and time.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'There are no black holes in the sense of regimes from which light can''t escape to infinity.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The universe is governed by science. But science tells us that we can''t solve the equations directly in the abstract.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Women. They are a complete mystery.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Science is not only a disciple of reason but, also, one of romance and passion.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The universe doesn''t allow perfection because a perfect universe would have had to begin perfectly, which is impossible.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'I believe the simplest explanation is there is no God. No one created the universe and no one directs our fate.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Hawking radiation is what I''m most proud of — a black hole should create and emit particles with a thermal spectrum.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The whole history of science has been the gradual realization that events do not happen in an arbitrary manner, but that they reflect a certain underlying order.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),

-- Niels Bohr (15 quotes)
(gen_random_uuid(), 'If quantum mechanics hasn''t profoundly shocked you, you haven''t understood it yet.', 'Niels Bohr', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'An expert is a person who has made all the mistakes that can be made in a very narrow field.', 'Niels Bohr', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Never express yourself more clearly than you are able to think.', 'Niels Bohr', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'focus', 'learning'], true, 'science'),
(gen_random_uuid(), 'It is wrong to think that the task of physics is to find out how nature is. Physics concerns what we can say about nature.', 'Niels Bohr', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The opposite of a correct statement is a false statement. But the opposite of a profound truth may well be another profound truth.', 'Niels Bohr', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Prediction is very difficult, especially about the future.', 'Niels Bohr', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'There is no quantum world. There is only an abstract quantum physical description.', 'Niels Bohr', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Every sentence I utter must be understood not as an affirmation, but as a question.', 'Niels Bohr', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The atoms or elementary particles themselves are not real; they form a world of potentialities or possibilities rather than one of things or facts.', 'Niels Bohr', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Technology has advanced more in the last thirty years than in the previous two thousand.', 'Niels Bohr', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The best weapon of a dictatorship is secrecy, but the best weapon of a democracy should be the weapon of openness.', 'Niels Bohr', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'A great truth is a truth whose opposite is also a great truth.', 'Niels Bohr', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Light and matter are both single entities, and the apparent duality arises in the limitations of our language.', 'Niels Bohr', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Anyone who is not shocked by quantum theory has not understood it.', 'Niels Bohr', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Complementarity is the principle that matter and energy can be viewed as both particles and waves depending on the experimental context.', 'Niels Bohr', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),

-- Werner Heisenberg (10 quotes)
(gen_random_uuid(), 'The more precisely the position is determined, the less precisely the momentum is known in this instant, and vice versa.', 'Werner Heisenberg', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'What we observe is not nature itself, but nature exposed to our method of questioning.', 'Werner Heisenberg', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Natural science does not simply describe and explain nature; it is part of the interplay between nature and ourselves.', 'Werner Heisenberg', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The first gulp from the glass of natural sciences will turn you into an atheist, but at the bottom of the glass God is waiting for you.', 'Werner Heisenberg', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Not only is the universe stranger than we think, it is stranger than we can think.', 'Werner Heisenberg', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'In the history of science, ever since the famous trial of Galileo, it has repeatedly been claimed that scientific truth cannot be reconciled with the religious interpretation of the world.', 'Werner Heisenberg', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Uncertainty is the only certainty there is, and knowing how to live with insecurity is the only security.', 'Werner Heisenberg', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'self_improvement', 'learning'], true, 'science'),
(gen_random_uuid(), 'We have to remember that what we observe is not nature in itself but nature exposed to our method of questioning.', 'Werner Heisenberg', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Every experiment destroys some of the knowledge of the system which was obtained by previous experiments.', 'Werner Heisenberg', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'An expert is somebody who knows some of the worst mistakes that can be made in his subject and how to avoid them.', 'Werner Heisenberg', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),

-- Isaac Newton (15 quotes)
(gen_random_uuid(), 'If I have seen further it is by standing on the shoulders of Giants.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'To every action there is always opposed an equal reaction.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Gravity explains the motions of the planets, but it cannot explain who sets the planets in motion.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'What we know is a drop, what we don''t know is an ocean.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Tact is the knack of making a point without making an enemy.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'self_improvement', 'learning'], true, 'science'),
(gen_random_uuid(), 'Plato is my friend — Aristotle is my friend — but my greatest friend is truth.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Nature is pleased with simplicity. And nature is no dummy.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'I can calculate the motion of heavenly bodies, but not the madness of people.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Truth is ever to be found in simplicity, and not in the multiplicity and confusion of things.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'focus', 'learning'], true, 'science'),
(gen_random_uuid(), 'No great discovery was ever made without a bold guess.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'I do not know what I may appear to the world, but to myself I seem to have been only like a boy playing on the sea-shore.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The most beautiful system of the sun, planets and comets, could only proceed from the counsel and dominion of an intelligent Being.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'An object in motion stays in motion unless acted upon by an outside force.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['discipline', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Every body persists in its state of being at rest or of moving uniformly straight forward, except insofar as it is compelled to change its state by force impressed.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'discipline', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Errors are not in the art but in the artificers.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'self_improvement', 'learning'], true, 'science'),

-- Max Planck (10 quotes)
(gen_random_uuid(), 'Science cannot solve the ultimate mystery of nature. And that is because, in the last analysis, we ourselves are part of nature.', 'Max Planck', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'An important scientific innovation rarely makes its way by gradually winning over and converting its opponents: What does happen is that its opponents gradually die out.', 'Max Planck', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'A new scientific truth does not triumph by convincing its opponents and making them see the light, but rather because its opponents eventually die.', 'Max Planck', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'The photon has zero rest mass and always travels at the speed of light.', 'Max Planck', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'When you change the way you look at things, the things you look at change.', 'Max Planck', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'self_improvement', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'I regard consciousness as fundamental. I regard matter as derivative from consciousness.', 'Max Planck', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The assumption of an absolute determinism is the essential foundation of every scientific enquiry.', 'Max Planck', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Energy is not continuous, but comes in small but definite units called quanta.', 'Max Planck', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The natural world is not something external to and independent of ourselves — and what we observe in nature is inextricably linked to how we go about observing it.', 'Max Planck', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Physical laws are the most fundamental of all natural laws, in that all other natural laws can be reduced to them.', 'Max Planck', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'wisdom', 'curiosity'], true, 'science'),

-- Erwin Schrödinger (8 quotes)
(gen_random_uuid(), 'The present moment always will have been.', 'Erwin Schrödinger', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Consciousness cannot be accounted for in physical terms. For consciousness is absolutely fundamental.', 'Erwin Schrödinger', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The world is given to me only once, not one existing and one perceived. Subject and object are only one.', 'Erwin Schrödinger', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'In an honest search for knowledge you quite often have to abide by ignorance for an indefinite period.', 'Erwin Schrödinger', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'If you cannot — in the long run — tell everyone what you have been doing, your doing has been worthless.', 'Erwin Schrödinger', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'discipline'], true, 'science'),
(gen_random_uuid(), 'The task is not so much to see what no one has yet seen, but to think what no one has yet thought about that which everybody sees.', 'Erwin Schrödinger', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Quantum physics thus reveals a basic oneness of the universe.', 'Erwin Schrödinger', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The scientist only imposes two things, namely truth and sincerity, imposes them upon himself and upon other scientists.', 'Erwin Schrödinger', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'discipline', 'learning'], true, 'science'),

-- Paul Dirac (8 quotes)
(gen_random_uuid(), 'A theory with mathematical beauty is more likely to be correct than an ugly one that fits some experimental data.', 'Paul Dirac', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'In science one tries to tell people, in such a way as to be understood by everyone, something that no one ever knew before.', 'Paul Dirac', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'God used beautiful mathematics in creating the world.', 'Paul Dirac', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Mathematics is the tool specially suited for dealing with abstract concepts of any kind and there is no limit to its power in this field.', 'Paul Dirac', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Pick a flower on Earth and you move the farthest star.', 'Paul Dirac', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The laws of nature should be expressed by beautiful equations.', 'Paul Dirac', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The underlying physical laws necessary for the mathematical theory of a large part of physics and the whole of chemistry are thus completely known.', 'Paul Dirac', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'If you are receptive and humble, mathematics will lead you by the hand.', 'Paul Dirac', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'self_improvement', 'wisdom'], true, 'science'),

-- Enrico Fermi (7 quotes)
(gen_random_uuid(), 'If I could remember the names of all these particles, I would have been a botanist.', 'Enrico Fermi', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'There are two possible outcomes: if the result confirms the hypothesis, then you''ve made a measurement. If the result is contrary to the hypothesis, then you''ve made a discovery.', 'Enrico Fermi', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'It is no good to try to stop knowledge from going forward. Ignorance is never better than knowledge.', 'Enrico Fermi', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'wisdom', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'The most up-to-date physics asks us to reconsider everything we think we know about the nature of matter.', 'Enrico Fermi', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Before I came here I was confused about this subject. Having listened to your lecture I am still confused. But on a higher level.', 'Enrico Fermi', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'When I was a student, the physics department at the university I attended considered nuclear physics to be a branch of applied science.', 'Enrico Fermi', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Where shall I look for the good, the great, the true? In the atom.', 'Enrico Fermi', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),

-- Nikola Tesla (8 quotes)
(gen_random_uuid(), 'The present is theirs; the future, for which I really worked, is mine.', 'Nikola Tesla', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['discipline', 'wisdom', 'focus'], true, 'science'),
(gen_random_uuid(), 'The day science begins to study non-physical phenomena, it will make more progress in one decade than in all the previous centuries of its existence.', 'Nikola Tesla', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'If you want to find the secrets of the universe, think in terms of energy, frequency and vibration.', 'Nikola Tesla', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Of all things, I liked books best.', 'Nikola Tesla', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Be alone, that is the secret of invention; be alone, that is when ideas are born.', 'Nikola Tesla', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'focus', 'discipline'], true, 'science'),
(gen_random_uuid(), 'The scientists of today think deeply instead of clearly. One must be sane to think clearly, but one can think deeply and be quite insane.', 'Nikola Tesla', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Our virtues and our failings are inseparable, like force and matter. When they separate, man is no more.', 'Nikola Tesla', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'self_improvement', 'learning'], true, 'science'),
(gen_random_uuid(), 'My brain is only a receiver, in the Universe there is a core from which we obtain knowledge, strength and inspiration.', 'Nikola Tesla', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),

-- Michael Faraday (7 quotes)
(gen_random_uuid(), 'The important thing in science is not so much to obtain new facts as to discover new ways of thinking about them.', 'Michael Faraday', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Nothing is too wonderful to be true if it be consistent with the laws of nature.', 'Michael Faraday', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The chemical history of a candle is a masterwork of nature.', 'Michael Faraday', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Magnetic lines of force have a physical existence and electromagnetism is mediated through a field.', 'Michael Faraday', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Water is to me, I confess, a phenomenon which continually awakens new feelings of wonder as often as I view it.', 'Michael Faraday', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The five essential entrepreneurial skills for success: concentration, discrimination, organization, innovation and communication.', 'Michael Faraday', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['discipline', 'focus', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'A man who is certain he is right is almost sure to be wrong.', 'Michael Faraday', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'self_improvement', 'learning'], true, 'science'),

-- James Clerk Maxwell (7 quotes)
(gen_random_uuid(), 'The true logic of this world is in the calculus of probabilities.', 'James Clerk Maxwell', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'It is a universal condition of the enjoyable that the mind must believe in the existence of a law, and yet have a mystery to move about in.', 'James Clerk Maxwell', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'All the mathematical sciences are founded on relations between physical laws and laws of numbers.', 'James Clerk Maxwell', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The special theory of the universe rests on the hypothesis that the fundamental laws of nature are the same in all inertial systems.', 'James Clerk Maxwell', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'An electron cannot be here one moment and there the next without passing through all the points in between, unless it takes a quantum leap.', 'James Clerk Maxwell', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The equations of electromagnetism are among the most beautiful in all of physics, unifying electricity, magnetism and light.', 'James Clerk Maxwell', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Every molecule therefore throughout the universe bears impressed upon it the stamp of a metric system as distinctly as does the metre of platinum.', 'James Clerk Maxwell', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),

-- Michio Kaku (10 quotes)
(gen_random_uuid(), 'The human brain has 100 billion neurons, each neuron connected to ten thousand other neurons. Sitting on your shoulders is the most complicated object in the known universe.', 'Michio Kaku', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'String theory is the theory of everything — a framework in which all fundamental forces and matter fields are modeled as modes of vibration of tiny supersymmetric strings.', 'Michio Kaku', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The multiverse is not a theory. It is a prediction of a theory, specifically the theory of inflation.', 'Michio Kaku', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The goal of physics is to find an equation no more than one inch long that would allow us to read the mind of God.', 'Michio Kaku', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Advances in science often begin with a question, not an answer.', 'Michio Kaku', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Dark energy is the biggest mystery in all of science. It makes up 73 percent of the universe yet we have no idea what it is.', 'Michio Kaku', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Black holes are where God divided by zero.', 'Michio Kaku', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'creativity'], true, 'science'),
(gen_random_uuid(), 'We are in the midst of the greatest technological revolution in human history — the internet of things, big data, artificial intelligence — and physics is the foundation of it all.', 'Michio Kaku', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Consciousness to me is being aware of your place in the universe.', 'Michio Kaku', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The universe is a symphony of strings, and the mind of God that Einstein wrote about is cosmic music resonating through eleven-dimensional hyperspace.', 'Michio Kaku', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),

-- Brian Greene (8 quotes)
(gen_random_uuid(), 'The Universe is out there, waiting for you to discover it.', 'Brian Greene', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The equations of physics have in them incredible simplicity, elegance and beauty.', 'Brian Greene', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Time moves forward because entropy — disorder — always increases. The direction of time is the direction of increasing entropy.', 'Brian Greene', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Black holes are the dark residue of collapsed stars, and their enigmatic nature captured imaginations everywhere.', 'Brian Greene', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The fabric of reality is not just space and time. It is also the quantum fields that permeate the universe.', 'Brian Greene', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'String theory is an attempt at a deeper description of nature by thinking of an elementary particle not as a little point but as a little loop of vibrating string.', 'Brian Greene', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'What we now know about the universe suggests that the cosmos is far stranger and far more beautiful than our ancestors ever imagined.', 'Brian Greene', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'In string theory, all particles are vibrations on a tiny rubber band; physics is the harmonics. The universe is a symphony.', 'Brian Greene', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),

-- Lisa Randall (7 quotes)
(gen_random_uuid(), 'The universe is a pretty big place. If it''s just us, seems like an awful waste of space.', 'Lisa Randall', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Extra dimensions of space would have profound implications for fundamental physics, including string theory.', 'Lisa Randall', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Science proceeds by setting up hypotheses — ideas or theories — and then testing them against observations of the natural world.', 'Lisa Randall', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Physics is the study of fundamental laws of nature and the way those laws affect everything around us.', 'Lisa Randall', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Dark matter''s gravitational influence on visible matter tells us it exists even though we can''t directly observe it.', 'Lisa Randall', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'We are made of stardust. The iron in our blood was forged in the hearts of stars that died before our sun was born.', 'Lisa Randall', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Warped dimensions could be the key to understanding why gravity is so much weaker than the other forces of nature.', 'Lisa Randall', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),

-- Carl Sagan (8 quotes, physics-focused)
(gen_random_uuid(), 'The nuclear arms race is like two sworn enemies standing waist deep in gasoline, one with three matches, the other with five.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'For small creatures such as we the vastness is bearable only through love.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'We live in a society exquisitely dependent on science and technology, in which hardly anyone knows anything about science and technology.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'The nitrogen in our DNA, the calcium in our teeth, the iron in our blood, the carbon in our apple pies were made in the interiors of collapsing stars.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Absence of evidence is not evidence of absence.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Our planet is a lonely speck in the great enveloping cosmic dark. In our obscurity, in all this vastness, there is no hint that help will come from elsewhere.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'If we long for our planet to be important, there is something we can do about it. We make our world significant by the courage of our questions and the depth of our answers.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'A central lesson of science is that to understand complex issues, we must try to free our minds of dogma.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),

-- Neil deGrasse Tyson (8 quotes, physics-focused)
(gen_random_uuid(), 'Equipped with his five senses, man explores the universe around him and calls the adventure Science.', 'Neil deGrasse Tyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Somewhere, something incredible is waiting to be known.', 'Neil deGrasse Tyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The atoms of our bodies are traceable to stars that manufactured them in their cores and exploded these enriched ingredients across our galaxy.', 'Neil deGrasse Tyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Stars explode. Galaxies collide. The universe is not a safe place.', 'Neil deGrasse Tyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Not only do we live among the stars, the stars live within us.', 'Neil deGrasse Tyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'We do not simply live in this universe. The universe lives within us.', 'Neil deGrasse Tyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The universe is under no obligation to make sense to you. But the joy of science is that it often does anyway.', 'Neil deGrasse Tyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'There is no shame in not knowing. The problem arises when irrational thought and attendant behavior fill the vacuum left by ignorance.', 'Neil deGrasse Tyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),

-- Roger Penrose (7 quotes)
(gen_random_uuid(), 'The laws of physics are the way that the physical world behaves, and mathematics is the language of those laws.', 'Roger Penrose', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Understanding is, after all, what science is all about — and science is a great deal more than mere mindless computation.', 'Roger Penrose', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'There is a certain sense in which I would say the universe has a purpose. It''s not there just somehow by chance.', 'Roger Penrose', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The singularity at the beginning of the universe is not the singular behavior of matter, it is the singular behavior of space-time itself.', 'Roger Penrose', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Consciousness is not a computation. It involves genuine understanding, genuine insight.', 'Roger Penrose', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The physical world is not merely mathematical; it is mathematical in a very deep and specific sense.', 'Roger Penrose', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Twistor theory is an attempt to reformulate the foundations of physics using complex numbers and geometry.', 'Roger Penrose', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'creativity'], true, 'science'),

-- Freeman Dyson (7 quotes)
(gen_random_uuid(), 'A good scientist is a person with original ideas. A good engineer is a person who makes a design that works with as few original ideas as possible.', 'Freeman Dyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The great papers of modern physics were not written by specialists but by amateurs, adventurers, and revolutionaries.', 'Freeman Dyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Progress in science comes when experiments contradict theory.', 'Freeman Dyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The technologies that will dominate the next fifty years are biology and genetics, not physics.', 'Freeman Dyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'In physics, you don''t have to go around making trouble for yourself; nature does it for you.', 'Freeman Dyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'It is characteristic of all deep human problems that they are not to be approached without some humor and some bewilderment.', 'Freeman Dyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The universe is not only queerer than we suppose, but queerer than we can suppose.', 'Freeman Dyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),

-- Murray Gell-Mann (6 quotes)
(gen_random_uuid(), 'If I have seen further than others, it is because I stood on the shoulders of nitwits.', 'Murray Gell-Mann', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Think how many beautiful theories have been spoiled by ugly facts.', 'Murray Gell-Mann', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The quark model is a classification scheme for hadrons in terms of their valence quarks — the quarks and antiquarks which give rise to the quantum numbers.', 'Murray Gell-Mann', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Symmetry is the key to understanding the laws of nature. When we see symmetry in nature, we know we''re on to something deep.', 'Murray Gell-Mann', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'In elementary particle physics, strangeness is a property of particles expressed as a quantum number for describing decay of particles in strong and electromagnetic interactions.', 'Murray Gell-Mann', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The quark was a crazy idea that turned out to be true — that is the best kind of idea in science.', 'Murray Gell-Mann', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),

-- Kip Thorne (6 quotes)
(gen_random_uuid(), 'Gravitational waves are ripples in the curvature of space-time that propagate as waves at the speed of light.', 'Kip Thorne', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The detection of gravitational waves is the greatest discovery of the century, perhaps of all time.', 'Kip Thorne', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Black holes are one of the most extreme objects in the universe — regions where space-time is so warped that even light cannot escape.', 'Kip Thorne', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Wormholes are tunnels through space-time that could in principle connect distant regions of the universe.', 'Kip Thorne', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The bending of light by gravity was one of the first confirmations of Einstein''s general theory of relativity.', 'Kip Thorne', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'I have always believed that the universe contains far more wonder than we have yet imagined — and that our job as scientists is to find it.', 'Kip Thorne', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),

-- J. Robert Oppenheimer (7 quotes)
(gen_random_uuid(), 'Now I am become Death, the destroyer of worlds.', 'J. Robert Oppenheimer', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The atomic bomb made the prospects of future war unendurable. It has led us up those last few steps to the mountain pass; and beyond there is a different country.', 'J. Robert Oppenheimer', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'The optimist thinks this is the best of all possible worlds. The pessimist fears it is true.', 'J. Robert Oppenheimer', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'There must be no barriers to freedom of inquiry. There is no place for dogma in science.', 'J. Robert Oppenheimer', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Science is not everything, but science is very beautiful.', 'J. Robert Oppenheimer', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The physicists have known sin; and this is a knowledge which they cannot lose.', 'J. Robert Oppenheimer', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Both the man of science and the man of art live always at the edge of mystery, surrounded by it; both always, as the measure of their creation, have had to do with the harmonization of what is new with what is familiar.', 'J. Robert Oppenheimer', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),

-- Ernest Rutherford (7 quotes)
(gen_random_uuid(), 'In science there is only physics; all the rest is stamp collecting.', 'Ernest Rutherford', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'All science is either physics or stamp collecting.', 'Ernest Rutherford', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'If your experiment needs statistics, you ought to have done a better experiment.', 'Ernest Rutherford', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'discipline', 'learning'], true, 'science'),
(gen_random_uuid(), 'The atom is the smallest indivisible unit of matter — or so we thought, until we discovered the nucleus.', 'Ernest Rutherford', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'We are all agreed that your theory is crazy. The question that divides us is whether it is crazy enough.', 'Ernest Rutherford', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'When we have found how the nucleus of atoms is built up we shall have found the greatest secret of all — except life.', 'Ernest Rutherford', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Of all created comforts, God is the lender; you are the borrower, not the owner.', 'Ernest Rutherford', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science')

ON CONFLICT (text, author) DO NOTHING;

